#!/usr/bin/env node

// src/cli.ts
import path2 from "path";
import { program } from "@commander-js/extra-typings";

// src/lib.ts
import AdmZip from "adm-zip";
import { exec } from "child_process";
import fs from "fs";
import path from "path";
function detectPackageManager(cwd) {
  let dir = cwd;
  for (let i = 0; i < 3; i++) {
    const hasFile = (name) => fs.existsSync(path.join(dir, name));
    if (hasFile("yarn.lock")) return "yarn";
    if (hasFile("pnpm-lock.yaml")) return "pnpm";
    if (hasFile("bun.lockb") || hasFile("bun.lock")) return "bun";
    if (hasFile("package-lock.json")) return "npm";
    const parent = path.dirname(dir);
    if (parent === dir) break;
    dir = parent;
  }
  return "npm";
}
function zipPluginDistribution(options) {
  const distPath = path.isAbsolute(options.distPath) ? options.distPath : path.join(options.cwd, options.distPath);
  if (!fs.existsSync(distPath)) {
    throw new Error(`${distPath} does not exist`);
  }
  if (!fs.statSync(distPath).isDirectory()) {
    throw new Error(`${distPath} is not directory`);
  }
  const zipFilePath = path.isAbsolute(options.zipFileName) ? options.zipFileName : path.join(options.cwd, options.zipFileName);
  const zip = new AdmZip();
  zip.addLocalFolder(distPath);
  zip.writeZip(zipFilePath);
  return zipFilePath;
}
function runPluginBuildScript(cwd, buildCommandOverride) {
  let buildCommand;
  if (buildCommandOverride) {
    buildCommand = buildCommandOverride;
    console.log(`Using custom build command: ${buildCommand}`);
  } else {
    const packageManager = detectPackageManager(cwd);
    console.log(`Detected package manager: ${packageManager}`);
    buildCommand = `${packageManager} run build`;
  }
  return new Promise((resolve, reject) => {
    const buildProcess = exec(buildCommand, { cwd });
    buildProcess.stdout?.on("data", (data) => process.stdout.write(data));
    buildProcess.stderr?.on("data", (data) => process.stderr.write(data));
    buildProcess.on("exit", (code) => {
      if (code !== 0) {
        reject(new Error(`Failed to build Plugin. Exit code: ${code ?? "unknown"}`));
        return;
      }
      resolve();
    });
    buildProcess.on("error", (err) => {
      reject(new Error(`Failed to start build process: ${err.message}`));
    });
  });
}

// src/cli.ts
var defaultDistDir = "dist";
var defaultOutputFilename = "plugin.zip";
var defaultCWD = process.cwd();
program.name("framer-plugin-tools").description("CLI tools for Framer Plugins").version("1.1.0");
program.command("pack").alias("prepare").description("Build and package your plugin into a zip file for submission to the Framer Marketplace").option("-C, --cwd <dir>", "plugin project directory", defaultCWD).option("-d, --dist-dir <dir>", "output directory of the build output", defaultDistDir).option("-b, --build-command <cmd>", "custom build command (e.g., 'npm run build:plugin')").option("--prebuilt", "skip the build step and only create the zip").option("-o, --output <filename>", "output zip filename", defaultOutputFilename).action(async (options) => {
  if (!options.prebuilt) {
    console.log("Building your Plugin\u2026");
    await runPluginBuildScript(options.cwd, options.buildCommand);
  }
  console.log(`Creating ${options.output} file\u2026`);
  const zipFilePath = zipPluginDistribution({
    cwd: options.cwd,
    distPath: options.distDir,
    zipFileName: options.output
  });
  const fileName = path2.basename(zipFilePath);
  const dirName = path2.dirname(zipFilePath);
  console.log(
    `
\u26A1\uFE0F ${fileName} file has been created in ${dirName} 
 Submit your Plugin on the Framer Marketplace: https://www.framer.com/marketplace/dashboard/plugins/`
  );
});
program.parse(process.argv);
